from flask import Flask, redirect, request, session, url_for
import requests
import jwt
import os
import secrets

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Configuration for OpenID Connect
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
AUTHORIZATION_ENDPOINT = 'https://provider.com/authorize'
TOKEN_ENDPOINT = 'https://provider.com/token'
USERINFO_ENDPOINT = 'https://provider.com/userinfo'
REDIRECT_URI = 'http://localhost:5000/callback'
ISSUER = 'https://provider.com/'

@app.route('/')
def home():
    return 'Welcome to the Flask OIDC App'

@app.route('/login')
def login():
    nonce = secrets.token_urlsafe(16)
    session['nonce'] = nonce
    authorization_url = (
        f"{AUTHORIZATION_ENDPOINT}?response_type=code&client_id={CLIENT_ID}"
        f"&redirect_uri={REDIRECT_URI}&scope=openid&nonce={nonce}"
    )
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    nonce = session.pop('nonce', None)

    token_response = requests.post(
        TOKEN_ENDPOINT,
        data={
            'grant_type': 'authorization_code',
            'code': code,
            'redirect_uri': REDIRECT_URI,
            'client_id': CLIENT_ID,
            'client_secret': CLIENT_SECRET
        }
    )
    token_response_data = token_response.json()
    id_token = token_response_data.get('id_token')

    # Decode the ID token
    decoded_id_token = jwt.decode(id_token, options={"verify_signature": False})

    # Validate nonce
    if decoded_id_token.get('nonce') != nonce:
        return 'Invalid nonce', 400

    # Store user information in session
    session['user'] = {
        'sub': decoded_id_token.get('sub'),
        'name': decoded_id_token.get('name'),
        'email': decoded_id_token.get('email')
    }

    return redirect(url_for('profile'))

@app.route('/profile')
def profile():
    if 'user' not in session:
        return redirect(url_for('login'))
    user_info = session['user']
    return f"User Profile: {user_info}"

if __name__ == '__main__':
    app.run(debug=True)